options.getOption:
const BASE = window.location.origin;
const root = context.panel.chart.getDom();
root.innerHTML = '';
root.style.overflow = 'auto';

const css = document.createElement('style');
css.textContent = `
  .sim-card { background: rgba(0,188,212,0.06); border: 1px solid rgba(0,188,212,0.25); border-radius: 10px; padding: 14px; margin-bottom: 10px; }
  .sim-card h4 { margin: 0 0 4px; font-size: 13px; color: #00e5ff; font-family: 'Orbitron', sans-serif; letter-spacing: 0.05em; }
  .sim-card p { margin: 0 0 8px; font-size: 11px; color: #888; }
  .sim-row { display: flex; align-items: center; gap: 8px; margin-bottom: 8px; flex-wrap: wrap; }
  .sim-btn { background: #00bcd4; color: #000; border: none; border-radius: 6px; padding: 6px 14px; font-size: 11px; font-weight: 700; cursor: pointer; font-family: 'Share Tech Mono', monospace; }
  .sim-btn:hover { background: #00e5ff; }
  .sim-btn.red { background: #e53935; color: #fff; }
  .sim-btn.red:hover { background: #ff5252; }
  .sim-btn.amber { background: #ff9800; color: #000; }
  .sim-btn.amber:hover { background: #ffb74d; }
  .sim-btn:disabled { opacity: 0.4; cursor: not-allowed; }
  .sim-slider { width: 120px; accent-color: #00bcd4; }
  .sim-label { font-size: 11px; color: #aaa; min-width: 80px; font-family: 'Share Tech Mono', monospace; }
  .sim-val { font-size: 11px; color: #00e5ff; min-width: 30px; text-align: right; font-family: 'Share Tech Mono', monospace; }
  .sim-input { background:#111; border:1px solid #333; color:#eee; padding:4px 8px; border-radius:4px; font-size:11px; font-family:'Share Tech Mono',monospace; }
  .sim-log { background: #0a0a0a; border: 1px solid #222; border-radius: 8px; padding: 10px; margin-top: 10px; max-height: 180px; overflow-y: auto; font-size: 11px; font-family: 'Share Tech Mono', monospace; color: #ccc; }
  .sim-log .entry { padding: 3px 0; border-bottom: 1px solid #1a1a1a; }
  .sim-log .ts { color: #555; margin-right: 6px; }
  .sim-log .ok { color: #00e5ff; }
  .sim-log .err { color: #e53935; }
  .sim-log .warn { color: #ff9800; }
`;
root.appendChild(css);

const logData = [];
let logEl;
function addLog(msg, cls) {
  const ts = new Date().toLocaleTimeString();
  logData.unshift({ts, msg, cls: cls || 'ok'});
  if (logData.length > 50) logData.length = 50;
  if (logEl) logEl.innerHTML = logData.map(e => '<div class="entry"><span class="ts">' + e.ts + '</span><span class="' + e.cls + '">' + e.msg + '</span></div>').join('');
}

function makeCard(title, desc) {
  const c = document.createElement('div'); c.className = 'sim-card';
  c.innerHTML = '<h4>' + title + '</h4><p>' + desc + '</p>';
  return c;
}
function makeSlider(label, min, max, val, onChange) {
  const r = document.createElement('div'); r.className = 'sim-row';
  r.innerHTML = '<span class="sim-label">' + label + '</span><input type="range" class="sim-slider" min="' + min + '" max="' + max + '" value="' + val + '"><span class="sim-val">' + val + '</span>';
  const sl = r.querySelector('input'), sv = r.querySelector('.sim-val');
  sl.oninput = () => { sv.textContent = sl.value; if (onChange) onChange(+sl.value); };
  return { el: r, get: () => +sl.value };
}
function makeBtn(text, cls) {
  const b = document.createElement('button'); b.className = 'sim-btn ' + (cls||''); b.textContent = text;
  return b;
}

// ── Trigger Error ──
const c1 = makeCard('TRIGGER ERROR', 'Hit /test-error once to generate a 500 response');
const b1 = makeBtn('Fire 500', 'red');
b1.onclick = () => {
  b1.disabled = true;
  fetch(BASE + '/test-error').then(r => {
    addLog('/test-error \u2192 ' + r.status, r.status >= 500 ? 'err' : 'ok');
    b1.disabled = false;
  }).catch(e => { addLog('Error: ' + e.message, 'err'); b1.disabled = false; });
};
c1.appendChild(b1); root.appendChild(c1);

// ── Error Burst ──
const c2 = makeCard('ERROR BURST', 'Fire N requests to /test-error to spike the error rate metric');
const sl2 = makeSlider('Count', 5, 200, 20);
c2.appendChild(sl2.el);
const b2 = makeBtn('Fire Burst', 'red');
b2.onclick = () => {
  b2.disabled = true; b2.textContent = 'Firing...';
  const count = sl2.get();
  let ok = 0, fail = 0, done = 0;
  for (let i = 0; i < count; i++) {
    fetch(BASE + '/test-error').then(r => {
      if (r.status >= 500) fail++; else ok++;
      if (++done >= count) { addLog('Burst: ' + fail + ' errors / ' + (fail+ok) + ' total', fail > 0 ? 'err' : 'ok'); b2.disabled = false; b2.textContent = 'Fire Burst'; }
    }).catch(() => { fail++; if (++done >= count) { addLog('Burst: ' + fail + ' errors / ' + (fail+ok) + ' total', 'err'); b2.disabled = false; b2.textContent = 'Fire Burst'; } });
  }
};
c2.appendChild(b2); root.appendChild(c2);

// ── Traffic Spike ──
const c3 = makeCard('TRAFFIC SPIKE', 'Instant burst of concurrent GET /health requests');
const sl3 = makeSlider('Requests', 10, 500, 50);
c3.appendChild(sl3.el);
const b3 = makeBtn('Spike', 'amber');
b3.onclick = () => {
  b3.disabled = true; b3.textContent = 'Spiking...';
  const count = sl3.get(), t0 = Date.now();
  let done = 0, oks = 0;
  for (let i = 0; i < count; i++) {
    fetch(BASE + '/health').then(r => {
      if (r.status === 200) oks++;
      if (++done >= count) { const ms = Date.now() - t0; addLog('Spike: ' + oks + '/' + count + ' ok in ' + ms + 'ms (' + Math.round(count/(ms/1000)) + ' rps)', 'ok'); b3.disabled = false; b3.textContent = 'Spike'; }
    }).catch(() => { if (++done >= count) { const ms = Date.now() - t0; addLog('Spike: ' + oks + '/' + count + ' ok in ' + ms + 'ms', 'warn'); b3.disabled = false; b3.textContent = 'Spike'; } });
  }
};
c3.appendChild(b3); root.appendChild(c3);

// ── Concurrent Users ──
const c4 = makeCard('CONCURRENT USERS', 'Simulate N users hitting random endpoints for a set duration');
const sl4a = makeSlider('Users', 1, 200, 10);
const sl4b = makeSlider('Duration (s)', 1, 30, 5);
c4.appendChild(sl4a.el); c4.appendChild(sl4b.el);
const b4 = makeBtn('Start Load', '');
b4.onclick = () => {
  const users = sl4a.get(), dur = sl4b.get() * 1000;
  b4.disabled = true; b4.textContent = 'Running ' + (dur/1000) + 's...';
  const eps = ['/health', '/users?per_page=5', '/urls?per_page=5', '/events?per_page=5'];
  const end = Date.now() + dur;
  let total = 0, errs = 0, active = users;
  const lats = [];
  function loop() {
    if (Date.now() >= end) { if (--active <= 0) finish(); return; }
    const ep = eps[Math.floor(Math.random() * eps.length)], t0 = Date.now();
    fetch(BASE + ep).then(r => { lats.push(Date.now() - t0); total++; if (r.status >= 500) errs++; loop(); }).catch(() => { errs++; total++; loop(); });
  }
  function finish() {
    lats.sort((a,b) => a - b);
    const p50 = lats[Math.floor(lats.length*0.5)]||0, p95 = lats[Math.floor(lats.length*0.95)]||0;
    addLog('Load: ' + users + ' users, ' + total + ' reqs, ' + (total/(dur/1000)).toFixed(0) + ' rps, p50=' + p50 + 'ms p95=' + p95 + 'ms, err=' + (total ? ((errs/total)*100).toFixed(1) : '0') + '%', errs > 0 ? 'warn' : 'ok');
    b4.disabled = false; b4.textContent = 'Start Load';
  }
  for (let u = 0; u < users; u++) loop();
};
c4.appendChild(b4); root.appendChild(c4);

// ── Fire Alert ──
const c5 = makeCard('FIRE ALERT', 'Create an alert record in the Flask app database');
const r5 = document.createElement('div'); r5.className = 'sim-row';
r5.innerHTML = '<input placeholder="Alert name" class="sim-input" style="width:140px" id="sim-aname"><select class="sim-input" id="sim-asev"><option value="warning">warning</option><option value="critical">critical</option></select><input placeholder="Summary (optional)" class="sim-input" style="width:200px" id="sim-asum">';
c5.appendChild(r5);
const b5 = makeBtn('Fire Alert', 'red');
b5.onclick = () => {
  const nameEl = root.querySelector('#sim-aname'), sevEl = root.querySelector('#sim-asev'), sumEl = root.querySelector('#sim-asum');
  const name = nameEl.value.trim();
  if (!name) { addLog('Alert name required', 'err'); return; }
  b5.disabled = true;
  fetch(BASE + '/alerts', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({alert_name: name, severity: sevEl.value, summary: sumEl.value.trim() || undefined, source: 'grafana-simulate'}) })
    .then(r => r.json()).then(d => { addLog('Alert fired: ' + name + ' (' + sevEl.value + ') id=' + (d.id||'?'), 'ok'); nameEl.value = ''; sumEl.value = ''; b5.disabled = false; })
    .catch(e => { addLog('Alert error: ' + e.message, 'err'); b5.disabled = false; });
};
c5.appendChild(b5); root.appendChild(c5);

// ── Slow Endpoint ──
const c6 = makeCard('SLOW ENDPOINT', 'Hit an endpoint that sleeps server-side to spike p95 latency');
const sl6a = makeSlider('Delay (s)', 1, 10, 3);
const sl6b = makeSlider('Requests', 1, 50, 5);
c6.appendChild(sl6a.el); c6.appendChild(sl6b.el);
const b6 = makeBtn('Send Slow Requests', 'amber');
b6.onclick = () => {
  b6.disabled = true; b6.textContent = 'Sending...';
  const delay = sl6a.get(), n = sl6b.get();
  let done = 0, ok = 0;
  for (let i = 0; i < n; i++) {
    fetch(BASE + '/test-slow?delay=' + delay).then(r => { if (r.status < 500) ok++; if (++done >= n) { addLog('Slow: ' + ok + '/' + n + ' completed (' + delay + 's delay each)', 'warn'); b6.disabled = false; b6.textContent = 'Send Slow Requests'; } }).catch(() => { if (++done >= n) { addLog('Slow: ' + ok + '/' + n + ' completed (' + delay + 's delay each)', 'err'); b6.disabled = false; b6.textContent = 'Send Slow Requests'; } });
  }
};
c6.appendChild(b6); root.appendChild(c6);

// ── Log ──
logEl = document.createElement('div'); logEl.className = 'sim-log';
root.appendChild(logEl);
addLog('Simulation panel ready', 'ok');

return {};
